node -e "
const fs = require('fs');
const path = require('path');
const hoje = new Date().toISOString().slice(0,7);
const pastaRelatorio = path.join('relatorios', hoje);
if (!fs.existsSync(pastaRelatorio)) {
  fs.mkdirSync(pastaRelatorio, { recursive: true });
  console.log('PASTA_CRIADA: ' + pastaRelatorio);
}
const arquivosRaiz = fs.readdirSync('.').filter(f =>
  (f.endsWith('.md') || f.endsWith('.xlsx') || f.endsWith('.csv'))
  && f.includes('report') || f.includes('relatorio') || f.includes('kpi')
);
if (arquivosRaiz.length > 0) {
  arquivosRaiz.forEach(arq => {
    const destino = path.join(pastaRelatorio, arq);
    fs.renameSync(arq, destino);
    console.log('MOVIDO: ' + arq + ' → ' + destino);
  });
}
"
